sys_script.script:
(function executeRule(current, previous) {

    try {

        // Only for grouped alerts
        if (!current.parent)
            return;

        // Count alerts in same group
        var gr = new GlideRecord('em_alert');
        gr.addQuery('parent', current.parent);
        gr.addQuery('state', 'Open');
        gr.query();

        var count = gr.getRowCount();

        // Get related incident
        if (current.task) {
            var inc = new GlideRecord('incident');
            if (inc.get(current.task)) {

                // Escalation condition
                if (count >= 3) {

                    inc.priority = 1; // High
                    inc.urgency = 1;
                    inc.impact = 1;

                    // OPTIONAL: Change to escalation group
                    // inc.assignment_group = 'PUT_SYS_ID';

                    inc.work_notes = "Escalated automatically due to repeated alerts (" + count + ")";
                    inc.update();
                }
            }
        }

    } catch (e) {
        gs.error("Escalation Error: " + e.message);
    }

})(current, previous);
